#include<bits/stdc++.h>
using namespace std;
long long p,q,a1,a2,n,m;
struct matrix
{
    long long a[3][3];
    matrix()
    {
        memset(a,0,sizeof(a));
    }
    friend matrix operator*(const matrix&a,const matrix&b)
    {
        matrix c;
        for(long long i=1;i<=2;i++)
        {
            for(long long j=1;j<=2;j++)
            {
                for(long long k=1;k<=2;k++)
                {
                    c.a[i][j]+=1ll*(a.a[i][k]%m)*(b.a[k][j]%m)%m;
                    c.a[i][j]%=m;
                }
            }
        }
        return c;
    }
}base,ans;
void fastpow(long long y)
{
    for(long long i=1;i<=2;i++)
    {
        ans.a[i][i]=1;
    }
    while(y)
    {
        if(y%2==1)
        {
            ans=ans*base;
        }
        base=base*base;
        y/=2;
    }
}
int main()
{
    scanf("%lld%lld%lld%lld%lld%lld",&p,&q,&a1,&a2,&n,&m);
    if(n==1)
    {
        printf("%lld",a1%m);
        return 0;
    }
    if(n==2)
    {
        printf("%lld",a2%m);
        return 0;
    }
    base.a[1][1]=p;
    base.a[1][2]=q;
    base.a[2][1]=1;
    fastpow(n-2);
    printf("%lld",(ans.a[1][1]*a2%m+ans.a[1][2]*a1%m)%m);
    return 0;
}
